"""
This module manages the game state, player turns, and win/draw conditions.
"""
from board import Board, Piece

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'

    def play(self):
        while True:
            print(self.board)
            move = input(f"Player {self.current_player}, enter your move (e.g., 23-45): ")
            from_pos, to_pos = map(int, move.split('-'))
            if self.board.is_valid_move((from_pos // 10 - 1, from_pos % 10), (to_pos // 10 - 1, to_pos % 10)):
                self.board.move_piece((from_pos // 10 - 1, from_pos % 10), (to_pos // 10 - 1, to_pos % 10))
            else:
                print("Invalid move. Please try again.")
                continue

            # Check for win/draw conditions
            if self.check_win():
                print(f"Player {self.current_player} wins!")
                break

            # Switch turns
            self.current_player = 'red' if self.current_player == 'black' else 'black'

    def check_win(self):
        black_pieces = np.sum(np.array([isinstance(piece, Piece) and piece.color == 'black' for row in self.board.board for piece in row]))
        red_pieces = np.sum(np.array([isinstance(piece, Piece) and piece.color == 'red' for row in self.board.board for piece in row]))

        return black_pieces == 0 or red_pieces == 0
